import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';

export default function Navbar() {
  const [scrolled, setScrolled] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    setMenuOpen(false);
    window.scrollTo(0, 0);
  }, [location]);

  const navLinks = [
    { to: '/', label: 'Home' },
    { to: '/coaching', label: 'Coaching' },
    { to: '/about', label: 'About' },
    { to: '/contact', label: 'Contact' },
  ];

  const isActive = (to) => {
    if (to === '/') return location.pathname === '/';
    return location.pathname.startsWith(to);
  };

  return (
    <nav style={{
      position: 'fixed',
      top: 0, left: 0, right: 0,
      zIndex: 100,
      padding: '0 24px',
      height: '68px',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      background: scrolled ? 'rgba(7,3,26,0.85)' : 'transparent',
      backdropFilter: scrolled ? 'blur(20px)' : 'none',
      borderBottom: scrolled ? '1px solid rgba(255,255,255,0.06)' : 'none',
      transition: 'all 0.3s ease',
    }}>
      {/* Logo */}
      <Link to="/" style={{ display: 'flex', alignItems: 'baseline', gap: '6px', textDecoration: 'none' }}>
        <span style={{
          fontFamily: "'Playfair Display', serif",
          fontSize: '18px',
          fontWeight: 700,
          color: '#f8f6ff',
          letterSpacing: '-0.02em',
        }}>Fayzan Rab</span>
        <span style={{
          fontSize: '11px',
          fontWeight: 600,
          letterSpacing: '0.1em',
          background: 'linear-gradient(135deg, #8b5cf6, #06b6d4)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          backgroundClip: 'text',
        }}>MD PCC</span>
      </Link>

      {/* Desktop Nav */}
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }} className="desktop-nav">
        {navLinks.map(({ to, label }) => (
          <Link
            key={to}
            to={to}
            style={{
              padding: '7px 16px',
              borderRadius: '100px',
              fontSize: '14px',
              fontWeight: 500,
              color: isActive(to) ? '#f8f6ff' : 'rgba(248,246,255,0.6)',
              background: isActive(to) ? 'rgba(255,255,255,0.08)' : 'transparent',
              transition: 'all 0.2s ease',
              textDecoration: 'none',
            }}
          >
            {label}
          </Link>
        ))}
        <Link
          to="/contact"
          style={{
            marginLeft: '8px',
            padding: '9px 22px',
            borderRadius: '100px',
            fontSize: '14px',
            fontWeight: 600,
            background: 'linear-gradient(135deg, #f97316, #ec4899)',
            color: '#fff',
            textDecoration: 'none',
            boxShadow: '0 0 20px rgba(249,115,22,0.3)',
            transition: 'all 0.25s ease',
          }}
        >
          Work with me
        </Link>
      </div>

      {/* Mobile hamburger */}
      <button
        onClick={() => setMenuOpen(!menuOpen)}
        style={{
          display: 'none',
          flexDirection: 'column',
          gap: '5px',
          padding: '4px',
          background: 'none',
          border: 'none',
          cursor: 'pointer',
        }}
        className="hamburger"
        aria-label="Toggle menu"
      >
        {[0, 1, 2].map(i => (
          <span key={i} style={{
            display: 'block',
            width: '22px',
            height: '2px',
            background: '#f8f6ff',
            borderRadius: '2px',
            transition: 'all 0.3s ease',
          }} />
        ))}
      </button>

      {/* Mobile Menu */}
      {menuOpen && (
        <div style={{
          position: 'fixed',
          top: '68px', left: 0, right: 0,
          background: 'rgba(7,3,26,0.97)',
          backdropFilter: 'blur(20px)',
          padding: '24px',
          display: 'flex',
          flexDirection: 'column',
          gap: '4px',
          borderBottom: '1px solid rgba(255,255,255,0.06)',
        }}>
          {navLinks.map(({ to, label }) => (
            <Link
              key={to}
              to={to}
              style={{
                padding: '14px 16px',
                borderRadius: '10px',
                fontSize: '16px',
                fontWeight: 500,
                color: isActive(to) ? '#f8f6ff' : 'rgba(248,246,255,0.6)',
                background: isActive(to) ? 'rgba(255,255,255,0.06)' : 'transparent',
                textDecoration: 'none',
              }}
            >
              {label}
            </Link>
          ))}
          <Link
            to="/contact"
            style={{
              marginTop: '12px',
              padding: '14px 22px',
              borderRadius: '100px',
              fontSize: '15px',
              fontWeight: 600,
              background: 'linear-gradient(135deg, #f97316, #ec4899)',
              color: '#fff',
              textDecoration: 'none',
              textAlign: 'center',
            }}
          >
            Work with me
          </Link>
        </div>
      )}

      <style>{`
        @media (max-width: 768px) {
          .desktop-nav { display: none !important; }
          .hamburger { display: flex !important; }
        }
      `}</style>
    </nav>
  );
}
